create table dirkspzm32.tms_kunden_auftr_pos (
    sid                 varchar2(2 char) default '01' not null enable,
    firma_nr            number(6, 0) default 1 not null enable,
    kunden_auftr_pos_id number(*, 0) not null enable,
    status              varchar2(10 char) default 'N' not null enable,
    auftrag_nr          number(*, 5) not null enable,
    pos_nr              number(*, 0) not null enable,
    upos_nr             number(*, 0),
    adress_id_rechn     number(*, 0),
    adress_id_liefer    number(*, 0),
    besteller           varchar2(10 char) not null enable,
    best_nr_kunde       varchar2(30 char),
    li_nr               number(*, 5),
    li_pos_nr           number(*, 0),
    erz_datum           date not null enable,
    erz_login_id        number(*, 0) not null enable,
    aend_datum          date,
    aend_login_id       number(*, 0),
    arbeitsplatz_id     number(*, 0),
    artikel_id          number(*, 0) not null enable,
    zeichnung_index     varchar2(10 char),
    fa_nr               number(*, 5),
    fa_ag               number(*, 0),
    fa_upos             number(*, 0),
    charge_id           number(*, 0),
    seriennr_id         number(*, 0),
    anbruch             varchar2(1 char) not null enable,
    min_mhd_tage        number(*, 12),
    min_reifezeit       number(*, 12),
    strategie           varchar2(10 char) default 'FIFO' not null enable,
    mhd                 date,
    order_info          varchar2(40 char),
    lvs_info            varchar2(40 char),
    soll_menge          number(*, 3) not null enable,
    plan_menge          number(*, 3) default 0 not null enable,
    ist_menge           number(*, 3) default 0 not null enable,
    menge_basis         varchar2(3 char),
    mengeneinheit       varchar2(10 char),
    quell_lagerorte     varchar2(200 char),
    ziel                varchar2(30 char),
    wae_ziel            varchar2(30 char) not null enable,
    freigabe            varchar2(1 char) default 'M' not null enable,
    freigabe_datum      date,
    freigegeben_datum   date,
    auftr_datum         date not null enable,
    liefer_datum        date,
    fertig_datum        date,
    prioritaet          number(*, 0) default 3 not null enable,
    lam_sel1            varchar2(30 char),
    lam_sel2            varchar2(30 char),
    lam_sel3            varchar2(30 char),
    lam_sel4            varchar2(30 char),
    lam_sel5            varchar2(30 char),
    lam_sel6            varchar2(30 char),
    lam_sel7            varchar2(30 char),
    lam_sel8            varchar2(30 char),
    lam_sel9            varchar2(30 char),
    lam_sel10           varchar2(30 char),
    prod_params         varchar2(4000 char)
);

alter table dirkspzm32.tms_kunden_auftr_pos
    add constraint pk_tms_kunden_auftr_pos primary key ( kunden_auftr_pos_id )
        using index enable;

alter table dirkspzm32.tms_kunden_auftr_pos
    add constraint uix_tms_kunden_auftr_pos_auf
        unique ( auftrag_nr,
                 pos_nr,
                 upos_nr )
            using index enable;


